# EVOLVE-BLOCK-START
import networkx as nx
import json
import os
import pandas as pd
from typing import Dict, List
import heapq


def search_algorithm(src, dsts, G, num_partitions):
    """
    Steiner tree heuristic: find minimum cost tree connecting src to all dsts.
    Since the evaluator counts each unique edge only once (broadcast model),
    we minimize sum of edge costs in the tree spanning {src} ∪ {dsts}.
    """
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))

    # Remove edges with None cost
    none_cost_edges = [(u, v) for u, v, d in h.edges(data=True) if d.get('cost') is None]
    h.remove_edges_from(none_cost_edges)

    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    terminals = set(dsts)

    # Steiner tree heuristic: iteratively add closest terminal to growing tree
    # Start with src in the tree
    tree_nodes = {src}
    tree_edges = []  # list of (u, v) edges in our tree
    remaining = set(dsts)

    # Precompute shortest paths from src to all nodes
    try:
        src_distances, src_paths = nx.single_source_dijkstra(h, src, weight='cost')
    except Exception:
        # Fallback to baseline if Dijkstra fails
        return _baseline_search(src, dsts, G, h, num_partitions, bc_topology)

    # Check all dsts are reachable
    unreachable = [d for d in dsts if d not in src_distances]
    if unreachable:
        return _baseline_search(src, dsts, G, h, num_partitions, bc_topology)

    # Greedy Steiner tree: iteratively add the terminal that is cheapest to connect
    # to the existing tree (considering paths through tree nodes as free)

    # Build shortest path costs from every node to help with tree extension
    # Use a more efficient approach: compute distances from all terminals
    terminal_distances = {}
    terminal_paths = {}

    all_nodes_of_interest = set(dsts) | {src}
    for node in all_nodes_of_interest:
        try:
            if node == src:
                terminal_distances[node] = src_distances
                terminal_paths[node] = src_paths
            else:
                d, p = nx.single_source_dijkstra(h, node, weight='cost')
                terminal_distances[node] = d
                terminal_paths[node] = p
        except Exception:
            pass

    # Also compute reverse distances (distances TO each node)
    # For directed graph, we need to find paths TO tree nodes from remaining terminals
    # Use reverse graph for this
    h_rev = h.reverse()
    rev_distances = {}
    for node in all_nodes_of_interest:
        try:
            d, p = nx.single_source_dijkstra(h_rev, node, weight='cost')
            rev_distances[node] = d  # rev_distances[node][x] = cost to go from x to node in original graph
        except Exception:
            rev_distances[node] = {}

    # Steiner tree construction using shortest path heuristic
    # For directed graphs: find tree rooted at src reaching all dsts
    # Strategy: build tree by greedily adding cheapest connection from tree to remaining terminal

    # tree_paths[dst] = path from src to dst in our tree
    tree_paths = {}

    while remaining:
        best_cost = float('inf')
        best_terminal = None
        best_path = None

        for terminal in remaining:
            # Find cheapest way to reach this terminal from any node in tree
            # We need: tree_node -> ... -> terminal, where tree_node is already in tree
            # Cost should only count NEW edges (not already in tree)

            # Simple approach: find shortest path from src to terminal
            # considering edges already in tree as zero-cost
            # This is complex, so use simpler heuristic:
            # For each tree node, cost = distance(tree_node, terminal) using original costs
            # But edges already in tree are "free" (shared)

            # Approximate: find the tree node closest to this terminal
            for tree_node in tree_nodes:
                if tree_node in terminal_distances and terminal in terminal_distances[tree_node]:
                    cost = terminal_distances[tree_node][terminal]
                    if cost < best_cost:
                        best_cost = cost
                        best_terminal = terminal
                        best_path = terminal_paths[tree_node][terminal]
                # Also check reverse (can we reach terminal from tree_node?)
                elif terminal in rev_distances and tree_node in rev_distances[terminal]:
                    # This means there's a path from tree_node to terminal with this cost
                    cost = rev_distances[terminal][tree_node]
                    if cost < best_cost:
                        best_cost = cost
                        best_terminal = terminal
                        # Need to reconstruct the path - use Dijkstra from tree_node
                        try:
                            _, path = nx.single_source_dijkstra(h, tree_node, terminal, weight='cost')
                            best_path = path
                        except Exception:
                            pass

        if best_terminal is None or best_path is None:
            # Fallback for unreachable terminals
            for terminal in remaining:
                if terminal in src_paths:
                    tree_paths[terminal] = src_paths[terminal]
            break

