            tree_nodes.add(node)

        # Record the full path from src to this terminal
        # We need path from src, not from tree_node
        # If best_path starts from src, great. Otherwise, combine.
        if best_path[0] == src:
            tree_paths[best_terminal] = best_path
        else:
            # Combine: path from src to best_path[0], then best_path
            tree_start = best_path[0]
            if tree_start in src_paths:
                prefix = src_paths[tree_start]
                tree_paths[best_terminal] = prefix + best_path[1:]
            else:
                # Find path through the tree
                # Look for a terminal whose path passes through tree_start
                found = False
                for prev_terminal, prev_path in tree_paths.items():
                    if tree_start in prev_path:
                        idx = prev_path.index(tree_start)
                        tree_paths[best_terminal] = prev_path[:idx+1] + best_path[1:]
                        found = True
                        break
                if not found:
                    # Fallback: use direct path from src
                    if best_terminal in src_paths:
                        tree_paths[best_terminal] = src_paths[best_terminal]
                    else:
                        tree_paths[best_terminal] = best_path

    # Now try to optimize: for each destination, check if there's a cheaper path
    # that reuses more existing tree edges
    tree_edge_set = set()
    for path in tree_paths.values():
        for i in range(len(path) - 1):
            tree_edge_set.add((path[i], path[i+1]))

    # Refine: for each terminal, find path using tree edges as zero-cost
    for terminal in dsts:
        if terminal not in tree_paths:
            if terminal in src_paths:
                tree_paths[terminal] = src_paths[terminal]
            continue

        # Try to find a better path that reuses more tree edges
        # Create modified graph where tree edges have zero cost
        h_mod = h.copy()
        for u, v in tree_edge_set:
            if h_mod.has_edge(u, v):
                h_mod[u][v]['cost'] = 0.0

        try:
            new_path = nx.dijkstra_path(h_mod, src, terminal, weight='cost')
            # Calculate new edge cost added (non-tree edges)
            new_added_cost = sum(
                h[new_path[i]][new_path[i+1]]['cost']
                for i in range(len(new_path) - 1)
                if (new_path[i], new_path[i+1]) not in tree_edge_set
                and h.has_edge(new_path[i], new_path[i+1])
            )
            old_added_cost = sum(
                h[tree_paths[terminal][i]][tree_paths[terminal][i+1]]['cost']
                for i in range(len(tree_paths[terminal]) - 1)
                if (tree_paths[terminal][i], tree_paths[terminal][i+1]) not in tree_edge_set
                and h.has_edge(tree_paths[terminal][i], tree_paths[terminal][i+1])
            )
            # Also check: old path edges that are in tree_edge_set but ONLY used by this terminal
            # would become "free" if we switch... this is complex, skip for now
            if new_added_cost < old_added_cost:
                tree_paths[terminal] = new_path
        except Exception:
            pass

    # Rebuild tree_edge_set after refinement
    tree_edge_set = set()
    for path in tree_paths.values():
        for i in range(len(path) - 1):
            tree_edge_set.add((path[i], path[i+1]))

    # Second pass refinement: now with updated tree edges, re-optimize each path
    for terminal in dsts:
        if terminal not in tree_paths:
            continue
        h_mod = h.copy()
        for u, v in tree_edge_set:
            if h_mod.has_edge(u, v):
                h_mod[u][v]['cost'] = 0.0
        try:
            new_path = nx.dijkstra_path(h_mod, src, terminal, weight='cost')
            tree_paths[terminal] = new_path
        except Exception:
            pass

    # Build the broadcast topology from our tree paths
    for dst in dsts:
        if dst in tree_paths:
            path = tree_paths[dst]
        elif dst in src_paths:
            path = src_paths[dst]
        else:
            continue

        for i in range(len(path) - 1):
            s, t = path[i], path[i + 1]
            edge_data = G[s][t] if G.has_edge(s, t) else h[s][t]
            for j in range(num_partitions):
                bc_topology.append_dst_partition_path(dst, j, [s, t, edge_data])

    return bc_topology


def _baseline_search(src, dsts, G, h, num_partitions, bc_topology):
    """Fallback to baseline Dijkstra approach."""
    for dst in dsts:
        try:
            path = nx.dijkstra_path(h, src, dst, weight="cost")
        except Exception:
            continue
        for i in range(len(path) - 1):
            s, t = path[i], path[i + 1]
            for j in range(num_partitions):
                bc_topology.append_dst_partition_path(dst, j, [s, t, G[s][t]])
    return bc_topology


class SingleDstPath(Dict):
    partition: int
    edges: List[List]  # [[src, dst, edge data]]


class BroadCastTopology:
    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, SingleDstPath] = None):
        self.src = src  # single str
        self.dsts = dsts  # list of strs
        self.num_partitions = num_partitions

        # dict(dst) --> dict(partition) --> list(nx.edges)
        # example: {dst1: {partition1: [src->node1, node1->dst1], partition 2: [src->dst1]}}
        if paths is not None:
            self.paths = paths
            self.set_graph()
        else:
            self.paths = {dst: {str(i): None for i in range(num_partitions)} for dst in dsts}

    def get_paths(self):
        print(f"now the set path is: {self.paths}")
        return self.paths

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def set_dst_partition_paths(self, dst: str, partition: int, paths: List[List]):
        """
        Set paths for partition = partition to reach dst
        """
        partition = str(partition)
        self.paths[dst][partition] = paths

    def append_dst_partition_path(self, dst: str, partition: int, path: List):
        """
        Append path for partition = partition to reach dst
        """
        partition = str(partition)
        if self.paths[dst][partition] is None:
            self.paths[dst][partition] = []
        self.paths[dst][partition].append(path)

def make_nx_graph(cost_path=None, throughput_path=None, num_vms=1):
    """
    Default graph with capacity constraints and cost info
    nodes: regions, edges: links
    per edge:
        throughput: max tput achievable (gbps)
        cost: $/GB
        flow: actual flow (gbps), must be < throughput, default = 0
    """
    # Use relative path from this file's location
    current_dir = os.path.dirname(os.path.abspath(__file__))

    if cost_path is None:
        cost = pd.read_csv(os.path.join(current_dir, "profiles/cost.csv"))
    else:
        cost = pd.read_csv(cost_path)

    if throughput_path is None:
        throughput = pd.read_csv(os.path.join(current_dir, "profiles/throughput.csv"))
    else:
        throughput = pd.read_csv(throughput_path)

    G = nx.DiGraph()
    for _, row in throughput.iterrows():
        if row["src_region"] == row["dst_region"]:
            continue
        G.add_edge(row["src_region"], row["dst_region"], cost=None, throughput=num_vms * row["throughput_sent"] / 1e9)

    for _, row in cost.iterrows():
        if row["src"] in G and row["dest"] in G[row["src"]]:
            G[row["src"]][row["dest"]]["cost"] = row["cost"]

    # some pairs not in the cost grid
    no_cost_pairs = []
    for edge in G.edges.data():
        src, dst = edge[0], edge[1]
        if edge[-1]["cost"] is None:
            no_cost_pairs.append((src, dst))
    print("Unable to get costs for: ", no_cost_pairs)

    return G


